from dataclasses import dataclass

class Token:
    def __init__(self, kind, value, line, col):
        self.kind = kind
        self.value = value
        self.line = line
        self.col = col

    def __repr__(self):
        return f"Token(kind='{self.kind}', value={self.value}, line={self.line}, col={self.col})"
